    const uint32_t HOut = H - Kh + 1;
    const uint32_t WOut = W - Kw + 1;

    const uint64_t totalOutput = static_cast<uint64_t>(N) * COut * HOut * WOut;

    // Choose a conservative blockDim
    uint32_t blockDim = 24u;
    if (totalOutput < blockDim) {
        blockDim = static_cast<uint32_t>(totalOutput);
        if (blockDim == 0u) blockDim = 1u;
