    int64_t W = x.size(3);
    int64_t Kh = weight.size(2);
    int64_t Kw = weight.size(3);
    TORCH_CHECK(Kh <= H && Kw <= W, "Kernel must not exceed input spatial dims without padding");
    at::Tensor result = at::empty({N, COut, H - Kh + 1, W - Kw + 1}, x.options());
    EXEC_NPU_CMD(aclnnConvStandard2dSquareInputAsymmetricKernelCustom, x, weight, result);
    return result;
